INSERT INTO site_settings (key, value_json, updated_at) VALUES ('about', '{"seoDescription":"个人介绍、兴趣、工具与站点时间线。","hero":{"eyebrow":"Hello, here is","introduction":"我把这里当作一间靠近海风的网络小屋：动画负责留下想象，代码负责搭好书架，日常则慢慢填满其中的空隙。写作不追赶热闹，只记录愿意再次回看的东西。","guestbookLabel":"在留言簿打招呼","rssLabel":"RSS 订阅"},"interests":{"eyebrow":"Interests · 喜欢的事","title":"在几条不同的路上，寻找相似的光","description":"兴趣不需要被整理成履历，它们更像长期陪伴写作的坐标。","items":[{"title":"动画与声音","description":"记录镜头、配乐和片尾之后仍然留下的情绪。"},{"title":"前端与写作","description":"把结构、可访问性与内容维护做成安静可靠的网页。"},{"title":"光影与日常","description":"收藏季节颜色、街角光线和不需要解释的小片段。"},{"title":"阅读与摘录","description":"用自己的问题回访长文，而不是只保存漂亮句子。"}]},"workbench":{"eyebrow":"Workbench · 常用工具","title":"轻量、可读，也方便明天继续整理","description":"工具的价值在于减少写作和维护之间的摩擦。这个站点使用 Astro SSR、运行时内容校验与少量浏览器脚本，让后台保存后的内容无需重建即可更新。","tools":["Astro","TypeScript","原生 CSS","Markdown","Content Collections","Playwright"]},"timeline":{"eyebrow":"Timeline · 小站时间线","title":"从第一块空白画布开始","description":"从 2026 年 7 月 15 日开始，记录这间小屋从页面雏形到数据库后台的真实开发过程。","entries":[{"date":"2026-07-15","title":"开始搭建个人博客","description":"创建 Astro 项目，确定 233昭 的站点身份与个人博客的基础页面结构。"},{"date":"2026-07-15","title":"确定二次元视觉方向","description":"加入首页人物主视觉、头像、动画交互，并持续调整人物构图与页面比例。"},{"date":"2026-07-16","title":"接入 SQLite 内容后台","description":"将文章、项目、分类、页面设置和友链迁移到统一数据库与单管理员后台。"},{"date":"2026-07-16","title":"开放友链与数据库留言","description":"完成友链增删改与排序，并加入访客留言提交、审核、公开和删除流程。"}]}}', '2026-07-17T00:00:00.000Z');
